package day4;

public class Program6_WhileBreak {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int i = 0;
		System.out.println("Hello");
		while (i <= 10) {
		
			System.out.print(i + " ");
			i++;

			if (i == 5) {
				break;

			}

		}
		System.out.println("\nBye");
	}

}
